 1	import React, { FC } from 'react';
 2	
 3	import { Stack, StackItem } from '@patternfly/react-core';
 4	
 5	import './VMsByNamespacePopover.scss';
 6	
 7	type VMsByNamespaceListProps = {
 8	  vmsByNamespace: { [p: string]: string[] };
 9	};
10	
11	const VMsByNamespacePopover: FC<VMsByNamespaceListProps> = ({ vmsByNamespace }) => (
12	  <div className="vm-by-namespace-popover">
13	    <Stack>
14	      {Object.keys(vmsByNamespace)
15	        ?.sort()
16	        ?.map((namespace, index) => {
17	          const vmNames = vmsByNamespace?.[namespace];
18	          return (
19	            <div className="vm-by-namespace-popover--namespace-group" key={`${namespace}-${index}`}>
20	              <StackItem>
21	                <b>{namespace}</b>
22	              </StackItem>
23	              {vmNames?.map((vmName, idx) => (
24	                <StackItem className="vm-by-namespace-popover--vmName" key={`${vmName}-${idx}`}>
25	                  {vmName}
26	                </StackItem>
27	              ))}
28	            </div>
29	          );
30	        })}
31	    </Stack>
32	  </div>
33	);
34	
35	export default VMsByNamespacePopover;

